// ── Año ganadero helpers ─────────────────────────────────────────────────────
function getAnoGanaderoActual() {
  const hoy = new Date();
  const año = hoy.getMonth() >= 6 ? hoy.getFullYear() : hoy.getFullYear() - 1;
  return `${año}/${año+1}`;
}


